import React, { useState, useMemo, useCallback } from 'react';

const T = {
  bg: '#0a0a0a', sf: '#111111', sf2: '#1a1a1a', bd: '#2a2a2a',
  tx: '#fafafa', tx2: '#a1a1aa', tx3: '#52525b',
  pur: '#8b5cf6', blu: '#38bdf8', yel: '#fbbf24', grn: '#22c55e',
  pnk: '#f472b6', org: '#fb923c', red: '#f87171',
};
const F = "'JetBrains Mono', monospace";

const BASE = [2.5, 2.3, 1.8, 1.0, 0.5];
const SP = [1.5, 1.5, 1.5, 1.5, 1.5];
const INIT_N = [0.3, -0.5, 0.8, -0.2, 1.0];
const ECOL = ['#38bdf8', '#8b5cf6', '#f472b6', '#fb923c', '#fbbf24'];

export default function App() {
  const [noise, setNoise] = useState([...INIT_N]);
  const [k, setK] = useState(2);
  const [drag, setDrag] = useState(null);

  const { H, probs, topIdx } = useMemo(() => {
    const H = BASE.map((b, i) => b + noise[i] * SP[i]);
    const pairs = H.map((v, i) => [v, i]).sort((a, b) => b[0] - a[0]);
    const top = pairs.slice(0, k).map(p => p[1]);
    const vals = top.map(i => H[i]);
    const mx = Math.max(...vals);
    const ex = vals.map(v => Math.exp(v - mx));
    const s = ex.reduce((a, b) => a + b, 0);
    const pr = H.map((_, i) => {
      const ti = top.indexOf(i);
      return ti >= 0 ? ex[ti] / s : 0;
    });
    return { H, probs: pr, topIdx: top };
  }, [noise, k]);

  const baseRank = [...BASE].map((v, i) => [v, i]).sort((a, b) => b[0] - a[0]).slice(0, k).map(p => p[1]);
  const noisyRank = [...topIdx].sort((a, b) => a - b);
  const baseTopSet = [...baseRank].sort((a, b) => a - b);
  const flipped = JSON.stringify(noisyRank) !== JSON.stringify(baseTopSet);

  const onDown = (idx, e) => {
    e.preventDefault();
    setDrag({ idx, sy: e.clientY, sv: noise[idx] });
  };

  const onMove = useCallback((e) => {
    if (!drag) return;
    const dy = drag.sy - e.clientY;
    const nv = Math.max(-2, Math.min(2, drag.sv + dy * 0.012));
    setNoise(p => { const n = [...p]; n[drag.idx] = nv; return n; });
  }, [drag]);

  const onUp = useCallback(() => setDrag(null), []);

  const rand = () => setNoise(Array(5).fill(0).map(() => +(Math.random() * 4 - 2).toFixed(2)));
  const rst = () => { setNoise([...INIT_N]); setK(2); };

  const best = probs.indexOf(Math.max(...probs));

  const handleY = (n) => 6 + (1 - (n + 2) / 4) * 68;

  return (
    <div
      style={{ maxWidth: 600, margin: '0 auto', padding: 16, fontFamily: F, color: T.tx, background: T.bg, minHeight: '100vh', userSelect: 'none', touchAction: 'none' }}
      onPointerMove={onMove} onPointerUp={onUp} onPointerLeave={onUp}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 700 }}>Noisy Top-K Gating</div>
          <div style={{ fontSize: 11, color: T.tx2, marginTop: 2 }}>Drag noise handles to re-route tokens to experts</div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button onClick={rand} style={{ background: T.sf2, border: '1px solid ' + T.bd, color: T.tx2, padding: '4px 10px', borderRadius: 6, cursor: 'pointer', fontFamily: F, fontSize: 11 }}>Shuffle</button>
          <button onClick={rst} style={{ background: T.sf2, border: '1px solid ' + T.bd, color: T.tx2, padding: '4px 10px', borderRadius: 6, cursor: 'pointer', fontFamily: F, fontSize: 11 }}>Reset</button>
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 14 }}>
        <span style={{ fontSize: 12, color: T.tx2 }}>Top-k:</span>
        {[1, 2, 3, 4, 5].map(v => (
          <button key={v} onClick={() => setK(v)}
            style={{ border: 'none', padding: '4px 12px', borderRadius: 6, cursor: 'pointer', fontFamily: F, fontSize: 12, fontWeight: 600, background: v === k ? T.pur : T.sf, color: v === k ? '#fff' : T.tx2, transition: 'all 0.2s' }}>
            {v}
          </button>
        ))}
        <span style={{ fontSize: 11, color: T.tx3, marginLeft: 6 }}>
          {k === 5 ? '(dense - all experts)' : k === 1 ? '(winner-take-all)' : '(' + k + ' experts active)'}
        </span>
      </div>

      <div style={{ background: T.sf, borderRadius: 12, padding: '14px 12px', border: '1px solid ' + T.bd }}>

        <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 6 }}>
          <div style={{ width: 62, fontSize: 10, color: T.tx3, textAlign: 'right', paddingRight: 6, flexShrink: 0 }}>Expert</div>
          <div style={{ display: 'flex', flex: 1, gap: 4 }}>
            {BASE.map((_, i) => (
              <div key={i} style={{ flex: 1, textAlign: 'center' }}>
                <div style={{ display: 'inline-block', width: 8, height: 8, borderRadius: '50%', background: ECOL[i], marginRight: 4, verticalAlign: 'middle' }}></div>
                <span style={{ fontSize: 12, fontWeight: 700, color: ECOL[i] }}>E{i + 1}</span>
              </div>
            ))}
          </div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 2 }}>
          <div style={{ width: 62, fontSize: 10, color: T.blu, textAlign: 'right', paddingRight: 6, flexShrink: 0, fontWeight: 600 }}>Base H</div>
          <div style={{ display: 'flex', flex: 1, gap: 4 }}>
            {BASE.map((b, i) => (
              <div key={i} style={{ flex: 1, textAlign: 'center', fontSize: 13, fontWeight: 600, color: T.tx, padding: '3px 0', background: T.bg, borderRadius: 4 }}>
                {b.toFixed(2)}
              </div>
            ))}
          </div>
        </div>

        <div style={{ textAlign: 'center', fontSize: 10, color: T.tx3, margin: '4px 0 2px', paddingLeft: 66 }}>+ noise * softplus</div>

        <div style={{ display: 'flex', alignItems: 'flex-start', gap: 4, marginBottom: 2 }}>
          <div style={{ width: 62, fontSize: 10, color: T.yel, textAlign: 'right', paddingRight: 6, flexShrink: 0, fontWeight: 600, paddingTop: 28 }}>
            Noise
            <div style={{ fontSize: 8, color: T.tx3, fontWeight: 400 }}>drag up/dn</div>
          </div>
          <div style={{ display: 'flex', flex: 1, gap: 4 }}>
            {noise.map((n, i) => {
              const hy = handleY(n);
              const cy = 40;
              const ft = Math.min(hy, cy);
              const fh = Math.abs(hy - cy);
              const contrib = n * SP[i];
              const isDragging = drag && drag.idx === i;
              return (
                <div key={i} style={{ flex: 1, textAlign: 'center' }}>
                  <div style={{ position: 'relative', width: '100%', height: 80, margin: '0 auto', maxWidth: 50 }}>
                    <div style={{ position: 'absolute', left: '50%', top: 6, bottom: 6, width: 2, background: T.bd, transform: 'translateX(-50%)', borderRadius: 1 }}></div>
                    <div style={{ position: 'absolute', left: '25%', right: '25%', top: cy, height: 1, background: T.tx3, opacity: 0.25 }}></div>
                    <div style={{
                      position: 'absolute', left: '50%', width: 5, transform: 'translateX(-50%)',
                      top: ft, height: Math.max(fh, 2), borderRadius: 2,
                      background: n >= 0 ? T.grn : T.org, opacity: 0.5,
                      transition: isDragging ? 'none' : 'all 0.15s',
                    }}></div>
                    <div
                      onPointerDown={(e) => onDown(i, e)}
                      style={{
                        position: 'absolute', left: '50%', transform: 'translate(-50%, -50%)',
                        top: hy, width: 18, height: 18, borderRadius: '50%',
                        background: n >= 0 ? T.grn : T.org,
                        border: isDragging ? '2px solid #fff' : '2px solid transparent',
                        cursor: 'ns-resize',
                        transition: isDragging ? 'none' : 'top 0.15s',
                        boxShadow: '0 0 10px ' + (n >= 0 ? T.grn : T.org) + '40',
                        zIndex: 2,
                      }}
                    ></div>
                  </div>
                  <div style={{ fontSize: 11, color: n >= 0 ? T.grn : T.org, fontWeight: 600, marginTop: 2 }}>
                    {n >= 0 ? '+' : ''}{n.toFixed(2)}
                  </div>
                  <div style={{ fontSize: 9, color: T.tx3 }}>
                    ({contrib >= 0 ? '+' : ''}{contrib.toFixed(2)})
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '2px 0' }}>
          <div style={{ width: 62 }}></div>
          <div style={{ flex: 1, height: 1, background: T.bd }}></div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 4, marginTop: 4 }}>
          <div style={{ width: 62, fontSize: 10, color: T.pnk, textAlign: 'right', paddingRight: 6, flexShrink: 0, fontWeight: 600 }}>Noisy H</div>
          <div style={{ display: 'flex', flex: 1, gap: 4 }}>
            {H.map((h, i) => {
              const sel = topIdx.includes(i);
              return (
                <div key={i} style={{
                  flex: 1, textAlign: 'center', fontSize: 13, fontWeight: 700, padding: '4px 0',
                  background: sel ? T.bg : 'transparent', borderRadius: 4,
                  color: sel ? ECOL[i] : T.tx3, opacity: sel ? 1 : 0.35,
                  transition: 'all 0.3s',
                  border: sel ? '1px solid ' + ECOL[i] + '40' : '1px solid transparent',
                }}>
                  {h.toFixed(2)}
                  <div style={{ fontSize: 8, fontWeight: 400, color: sel ? T.grn : T.red, marginTop: 1 }}>
                    {sel ? 'top-' + k : 'masked'}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div style={{ textAlign: 'center', fontSize: 10, color: T.tx3, margin: '2px 0', paddingLeft: 66 }}>
          softmax over top-{k}
        </div>

        <div style={{ display: 'flex', alignItems: 'flex-end', gap: 4, marginTop: 4 }}>
          <div style={{ width: 62, fontSize: 10, color: T.grn, textAlign: 'right', paddingRight: 6, flexShrink: 0, fontWeight: 600, paddingBottom: 20 }}>Gate</div>
          <div style={{ display: 'flex', flex: 1, gap: 4 }}>
            {probs.map((p, i) => {
              const sel = topIdx.includes(i);
              return (
                <div key={i} style={{ flex: 1, textAlign: 'center' }}>
                  <div style={{ position: 'relative', width: '100%', height: 50, background: T.bg, borderRadius: 6, overflow: 'hidden', maxWidth: 80, margin: '0 auto' }}>
                    <div style={{
                      position: 'absolute', bottom: 0, left: 2, right: 2,
                      height: p * 100 + '%',
                      background: sel ? ECOL[i] : T.tx3,
                      opacity: sel ? 0.75 : 0.1,
                      borderRadius: 4,
                      transition: 'all 0.35s ease',
                    }}></div>
                    {p > 0.01 && (
                      <div style={{
                        position: 'absolute', bottom: Math.max(p * 50, 2), left: 0, right: 0,
                        fontSize: 10, fontWeight: 700, color: '#fff',
                        textShadow: '0 1px 3px rgba(0,0,0,0.8)',
                        transition: 'all 0.35s',
                      }}>
                        {(p * 100).toFixed(0)}%
                      </div>
                    )}
                  </div>
                  <div style={{
                    fontSize: 11, fontWeight: 600, marginTop: 3,
                    color: sel ? T.tx : T.tx3,
                    transition: 'all 0.3s',
                  }}>
                    {(p * 100).toFixed(1)}%
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <div style={{
        marginTop: 10, padding: '10px 14px', borderRadius: 8,
        background: T.sf2, borderLeft: '3px solid ' + T.pur,
        fontSize: 12, color: T.tx2, lineHeight: 1.5,
      }}>
        <span style={{ color: T.pur, fontWeight: 600 }}>Insight: </span>
        {k === 1
          ? 'Winner-take-all: Expert ' + (best + 1) + ' gets 100%. Only one expert processes this token.'
          : k === 5
          ? 'Dense gating (k=5): all experts active. No sparsity - defeats the purpose of MoE efficiency!'
          : flipped
          ? 'Noise changed the selection! Without noise, top-' + k + ' would be ' + baseTopSet.map(i => 'E' + (i + 1)).join('+') + '. Now it is ' + noisyRank.map(i => 'E' + (i + 1)).join('+') + '. This helps explore different expert combinations.'
          : 'Selected: ' + topIdx.map(i => 'E' + (i + 1)).join(' + ') + ' (same as without noise). Try dragging noise to flip which experts are chosen!'
        }
      </div>

      <div style={{ marginTop: 8, padding: '8px 12px', borderRadius: 6, background: T.bg, fontSize: 10, color: T.tx3, textAlign: 'center' }}>
        Formula: H = X*Wg + N * Softplus(X*Wnoise)  |  Keep top-k  |  Softmax
      </div>
    </div>
  );
}
